pc <- read_tsv('./data/CPD_light.txt')

df <- GP_pc |> 
  select(Practice,PC5) |> 
  left_join(pc[c('PC5','X','Y','SA2011','AA2008NAME')])  |> 
  left_join(GP_lcg_fed)

pop_lookup <- df |> 
  filter(!is.na(Federation)) |> 
  select(AA2008NAME,Federation) |> 
  filter(!duplicated(AA2008NAME, Federation))

fed_pop <- pop |>
  left_join(pop_lookup, by = c('AA2008' = 'AA2008NAME')) |> 
  # filter(is.na(Federation)) |> #View()
  group_by(Federation) |> 
  summarise(over = sum(bmi%in%c('overweight','obese')),n=n()) |> 
  mutate(prev = over / n) |> 
  ungroup() 

lgd_pop <- pop |>
  # filter(is.na(Federation)) |> #View()
  group_by(LGD2014_name) |> 
  summarise(over = sum(bmi%in%c('overweight','obese')),n=n()) |>
  mutate(prev = over / n) |> 
  ungroup() 

lgd <- read_sf('LGD_2012.geojson')
lgd <- st_make_valid(lgd)
st_simplify(lgd)
lgd <- read_sf('OSNI_Open_Data_-_Largescale_Boundaries_-_Local_Government_Districts_(2012).kml')

ggplot(lgd) +
  geom_sf(aes(geometry=geometry))

x <- lgd |> 
  left_join(lgd_pop, by = c('LGDNAME' = 'LGD2014_name') 
            ) |> 
  select(geometry, prev,LGDNAME)

dep <- pop |> 
  group_by(LGD2014_name) |> 
  summarise(town=mean(custom_townsend_score_dz))

x <- x |> 
  left_join(dep , by = c('LGDNAME' = 'LGD2014_name'))

library(leaflet)

leaflet(x) |> 
  addTiles() |> 
  # addPolygons()
  addPolygons(fillColor = ~colorNumeric('YlGn', domain = x$town)(x$town),
              fillOpacity = 0.7,
              color = 'white',
              weight = 1,
              popup = ~paste0(LGDNAME,'<br>Deprivation: ',round(town,3))) |> 
  addLegend(pal = colorNumeric('YlGn', domain = x$town), values = x$town)


leaflet(x) |> 
  addTiles() |> 
  # addPolygons()
  addPolygons(fillColor = ~colorNumeric('YlOrRd', domain = x$prev)(x$prev),
              fillOpacity = 0.7,
              color = 'white',
              weight = 1,
              popup = ~paste0(LGDNAME,'<br>Prevalence: ',round(prev*100,1),'%')) |> 
  addLegend(pal = colorNumeric('YlOrRd', domain = x$prev), values = x$prev)


practices_sf <- df |>
  filter(!is.na(X)) |> 
  filter(!is.na(Federation)) |> 
    st_as_sf(coords = c("X", "Y"),
           crs = 29902,        # Irish Grid
           remove = FALSE) |>  # keep original X/Y columns
  st_transform(4326)          # WGS84 (lon/lat)

practices_sf




